#region Testing Mode
    # Helper to create the initial test images
    function New-TestImage-IfNotExists {
        param (
            [string]$ImagePath,
            [string]$ImageSize,
            [string]$MagickPath,
            [string]$CommandLogPath,
            [string]$TestingLogPath,
            [string]$Message
        )

        if (!(Test-Path $ImagePath)) {
            $arguments = "-size `"$ImageSize`" xc:#FC7E10 -background none `"$ImagePath`""
            $logEntry = "`"$MagickPath`" $arguments"
            $logEntry | Out-File $CommandLogPath -Append
            InvokeMagickCommand -Command $MagickPath -Arguments $arguments
            Write-Entry -Subtext $Message -Path $TestingLogPath -Color Cyan -log Info
        }
    }
    # Helper to build the Border/Overlay argument string
    function Get-BorderOverlay-Arguments {
        param (
            [string]$SourceImage,
            [string]$OutputPath,
            [string]$AddBorder,
            [string]$AddOverlay,
            [string]$OverlayImage,
            [string]$BorderWidthSecond,
            [string]$BorderColor,
            [string]$BorderWidth,
            [string]$LogPath
        )

        if ($AddBorder -eq 'true' -and $AddOverlay -eq 'true') {
            $logMessage = "Adding Borders | Adding Overlay"
            $arguments = "`"$SourceImage`" `"$OverlayImage`" -gravity south -quality $global:outputQuality -composite -shave `"$BorderWidthSecond`"  -bordercolor `"$BorderColor`" -border `"$BorderWidth`" `"$OutputPath`""
        }
        elseif ($AddBorder -eq 'true' -and $AddOverlay -eq 'false') {
            $logMessage = "Adding Borders"
            $arguments = "`"$SourceImage`" -shave `"$BorderWidthSecond`"  -bordercolor `"$BorderColor`" -border `"$BorderWidth`" `"$OutputPath`""
        }
        elseif ($AddBorder -eq 'false' -and $AddOverlay -eq 'true') {
            $logMessage = "Adding Overlay"
            $arguments = "`"$SourceImage`" `"$OverlayImage`" -gravity south -quality $global:outputQuality -composite `"$OutputPath`""
        }
        else {
            # If no borders or overlays, just copy/convert the source to the output path
            $logMessage = "No Border/Overlay - Creating base textless image"
            $arguments = "`"$SourceImage`" `"$OutputPath`""
        }

        Write-Entry -Subtext $logMessage -Path $LogPath -Color White -log Info
        return $arguments
    }
    # Helper to build the Text Overlay argument string
    function Get-TextOverlay-Arguments {
        param (
            [string]$AddStroke,
            [string]$InputFile,
            [string]$OutputFile,
            [string]$Font,
            [string]$PointSize,
            [string]$FontColor,
            [string]$BoxSize,
            [string]$LineSpacing,
            [string]$TextGravity,
            [string]$CaptionText,
            [string]$TextOffset,
            [string]$StrokeColor,
            [string]$StrokeWidth
        )

        if ($AddStroke -eq 'true') {
            # 1. Create solid color canvas (xc:).
            # 2. Create the stroke-only text layer (background none).
            # 3. Create the fill-only text layer (background none).
            # 4. Composite them in order: Background -> Stroke -> Fill.

            return "`"$InputFile`" -gravity center -background none -layers Flatten ( -size `"$BoxSize`" xc:`"#F3AC7C`" ( -font `"$Font`" -pointsize `"$PointSize`" -fill `"$StrokeColor`" -stroke `"$StrokeColor`" -strokewidth `"$StrokeWidth`" -size `"$BoxSize`" -background none -interline-spacing `"$LineSpacing`" -gravity `"$TextGravity`" caption:`"$CaptionText`" ) -gravity center -composite ( -font `"$Font`" -pointsize `"$PointSize`" -fill `"$FontColor`" -stroke none -size `"$BoxSize`" -background none -interline-spacing `"$LineSpacing`" -gravity `"$TextGravity`" caption:`"$CaptionText`" ) -gravity center -composite -trim +repage -extent `"$BoxSize`" ) -gravity south -geometry +0+`"$TextOffset`" -quality $global:outputQuality -composite `"$OutputFile`""
        }
        else {
            # Simple single-pass render. We can just set the background here.

            return "`"$InputFile`" -gravity center -background none -layers Flatten ( -font `"$Font`" -pointsize `"$PointSize`" -fill `"$FontColor`" -size `"$BoxSize`" -background `"#F3AC7C`" -interline-spacing `"$LineSpacing`" -gravity `"$TextGravity`" caption:`"$CaptionText`" -trim +repage -extent `"$BoxSize`" ) -gravity south -geometry +0+`"$TextOffset`" -quality $global:outputQuality -composite `"$OutputFile`""
        }
    }
    # Helper function to log and invoke
    function Invoke-MagickTestCommand {
        param([string]$Arguments, [string]$CommandLogPath)
        $logEntry = "`"$magick`" $Arguments"
        $logEntry | Out-File $CommandLogPath -Append
        InvokeMagickCommand -Command $magick -Arguments $Arguments
    }
    # =================================================================================
    # Initialization
    # =================================================================================

    $Mode = "testing"

    Write-Entry -Message "Poster Testing Started" -Path $global:configLogging -Color DarkMagenta -log Info
    Write-Entry -Subtext "I will now create a few posters for you with different text lengths using your current configuration settings." -Path $global:configLogging -Color Yellow -log Warning

    # Create Base Test Images
    New-TestImage-IfNotExists -ImagePath $testimage -ImageSize $PosterSize -MagickPath $magick -CommandLogPath $magickLog -TestingLogPath $global:configLogging -Message "Test Poster Created..."
    New-TestImage-IfNotExists -ImagePath $backgroundtestimage -ImageSize $BackgroundSize -MagickPath $magick -CommandLogPath $magickLog -TestingLogPath $global:configLogging -Message "Test Background/TitleCard Created..."

    # Base64 Overlay
    $favicon = ''
    $dir = Split-Path -LiteralPath $testimage
    $ovr = Join-Path $dir 'ovr_from_b64.png'
    $favicon = ($favicon -replace '\s', '')
    if ($favicon -like 'data:*') { $favicon = $favicon.Split(',', 2)[-1] }
    [IO.File]::WriteAllBytes($ovr, [Convert]::FromBase64String($favicon))

    foreach ($img in @($testimage, $backgroundtestimage)) {
        InvokeMagickCommand -Command $magick -Arguments @(
            $img, $ovr, '-gravity', 'center', '-compose', 'over', '-composite', $img
        )
    }
    if (Test-Path $ovr) { Remove-Item $ovr -Force }

    # =================================================================================
    # Define Test Cases
    # =================================================================================

    # Define Text Strings
    $ShortText = "The Hobbit"
    $MediumText = "The Hobbit is a great movie"
    $LongText = "The Hobbit is a great movie that we all loved and enjoyed watching"
    $bullet = [char]0x2022
    $Episodetext = "$SeasonTCText 9999 $bullet $EpisodeTCText 9999"

    # Define a single list of all test cases
    $testCases = @(
        [PSCustomObject]@{ ID = 'Short'; Text = $ShortText; VarSuffix = 'ShortText' }
        [PSCustomObject]@{ ID = 'Medium'; Text = $MediumText; VarSuffix = 'MediumText' }
        [PSCustomObject]@{ ID = 'Long'; Text = $LongText; VarSuffix = 'LongText' }
        [PSCustomObject]@{ ID = 'ShortCAPS'; Text = $ShortText.ToUpper(); VarSuffix = 'ShortTextCAPS' }
        [PSCustomObject]@{ ID = 'MediumCAPS'; Text = $MediumText.ToUpper(); VarSuffix = 'MediumTextCAPS' }
        [PSCustomObject]@{ ID = 'LongCAPS'; Text = $LongText.ToUpper(); VarSuffix = 'LongTextCAPS' }
    )

    $EpisodetextCAPS = $Episodetext.ToUpper()

    # =================================================================================
    # Generate Paths (Looping)
    # =================================================================================

    # Use Hashtables to store dynamic paths
    $posterPaths = @{}
    $showPosterPaths = @{}
    $seasonPosterPaths = @{}
    $backgroundPaths = @{}
    $showBackgroundPaths = @{}
    $titleCardPaths = @{}

    $testDir = Join-Path -Path $global:ScriptRoot -ChildPath "test"
    if (!(Test-Path $testDir)) {
        New-Item -ItemType Directory -Path $testDir -Force | Out-Null
    }

    if ($AddText -eq 'true') {
        $testCases | ForEach-Object { $posterPaths[$_.ID] = Join-Path $testDir "poster$($_.VarSuffix).jpg" }
        $testCases | ForEach-Object { $showPosterPaths[$_.ID] = Join-Path $testDir "showPoster$($_.VarSuffix).jpg" }
    }
    Else {
        $TestPosterTextless = Join-Path $testDir "PosterTextless.jpg"
        $TestShowPosterTextless = Join-Path $testDir "ShowPosterTextless.jpg"
    }

    if ($AddSeasonText -eq 'true') {
        $testCases | ForEach-Object { $seasonPosterPaths[$_.ID] = Join-Path $testDir "SeasonPoster$($_.VarSuffix).jpg" }
    }
    Else {
        $TestSeasonPosterTextless = Join-Path $testDir "SeasonPosterTextless.jpg"
    }

    if ($AddBackgroundText -eq 'true') {
        $testCases | ForEach-Object { $backgroundPaths[$_.ID] = Join-Path $testDir "background$($_.VarSuffix).jpg" }
        $testCases | ForEach-Object { $showBackgroundPaths[$_.ID] = Join-Path $testDir "showBackground$($_.VarSuffix).jpg" }
    }
    Else {
        $BackgroundTestPosterTextless = Join-Path $testDir "BackgroundTextless.jpg"
        $BackgroundTestShowPosterTextless = Join-Path $testDir "ShowBackgroundTextless.jpg"
    }

    if ($AddTitleCardEPTitleText -eq 'true' -or $AddTitleCardEPText -eq 'true') {
        $testCases | ForEach-Object { $titleCardPaths[$_.ID] = Join-Path $testDir "TitleCard$($_.VarSuffix).jpg" }
    }
    Else {
        $TitleCardTestPosterTextless = Join-Path $testDir "TitleCardTextless.jpg"
    }

    # =================================================================================
    # Calculate Font Sizes (Looping)
    # =================================================================================

    if ($AddText -eq 'true' -or $AddBackgroundText -eq 'true' -or $AddTitleCardEPTitleText -eq 'true' -or $AddTitleCardEPText -eq 'true') {
        Write-Entry -Subtext "Calculating Optimal Font Sizes. This may take a while..." -Path $global:configLogging -Color Cyan -log Info
    }

    $TruncatedCount = 0

    # Use Hashtables to store dynamic font sizes
    $posterFontSizes = @{}
    $showFontSizes = @{}
    $seasonFontSizes = @{}
    $backgroundFontSizes = @{}
    $titleCardFontSizes = @{}

    if ($AddText -eq 'true') {
        Write-Entry -Subtext "Finished Optimal Font Sizes for posters..." -Path $global:configLogging -Color Cyan -log Info
        foreach ($case in $testCases) {
            $posterFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $fontImagemagick -box_width $MaxWidth  -box_height $MaxHeight -min_pointsize $minPointSize -max_pointsize $maxPointSize -lineSpacing $lineSpacing
            if ($global:IsTruncated) { $TruncatedCount++ }
        }
    }

    if ($AddSeasonText -eq 'true') {
        if ($AddShowTitletoSeason -eq 'true') {
            # Title
            foreach ($case in $testCases) {
                $showFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $fontImagemagick -box_width $ShowOnSeasonMaxWidth  -box_height $ShowOnSeasonMaxHeight -min_pointsize $ShowOnSeasonminPointSize -max_pointsize $ShowOnSeasonmaxPointSize -lineSpacing $ShowOnSeasonlineSpacing
                if ($global:IsTruncated) { $TruncatedCount++ }
            }
            # Season
            foreach ($case in $testCases) {
                $seasonFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $fontImagemagick -box_width $SeasonMaxWidth  -box_height $SeasonMaxHeight -min_pointsize $SeasonminPointSize -max_pointsize $SeasonmaxPointSize -lineSpacing $SeasonlineSpacing
                if ($global:IsTruncated) { $TruncatedCount++ }
            }
        }
        Else {
            foreach ($case in $testCases) {
                $seasonFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $fontImagemagick -box_width $SeasonMaxWidth  -box_height $SeasonMaxHeight -min_pointsize $SeasonminPointSize -max_pointsize $SeasonmaxPointSize -lineSpacing $SeasonlineSpacing
                if ($global:IsTruncated) { $TruncatedCount++ }
            }
        }
        Write-Entry -Subtext "Finished Optimal Font Sizes for season posters..." -Path $global:configLogging -Color Cyan -log Info
    }

    if ($AddBackgroundText -eq 'true') {
        foreach ($case in $testCases) {
            $backgroundFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $backgroundfontImagemagick -box_width $BackgroundMaxWidth  -box_height $BackgroundMaxHeight -min_pointsize $BackgroundminPointSize -max_pointsize $BackgroundmaxPointSize -lineSpacing $BackgroundlineSpacing
            if ($global:IsTruncated) { $TruncatedCount++ }
        }
        Write-Entry -Subtext "Finished Optimal Font Sizes for backgrounds..." -Path $global:configLogging -Color Cyan -log Info
    }

    if ($AddTitleCardEPTitleText -eq 'true') {
        foreach ($case in $testCases) {
            $titleCardFontSizes[$case.ID] = Get-OptimalPointSize -text $case.Text -font $titlecardfontImagemagick -box_width $TitleCardEPTitleMaxWidth  -box_height $TitleCardEPTitleMaxHeight -min_pointsize $TitleCardEPTitleminPointSize -max_pointsize $TitleCardEPTitlemaxPointSize -lineSpacing $TitleCardEPTitlelineSpacing
            if ($global:IsTruncated) { $TruncatedCount++ }
        }
    }

    if ($AddTitleCardEPText -eq 'true') {
        $Episodetext = $Episodetext -replace 'â€ž', '"' -replace 'â€', '"' -replace 'â€œ', '"' -replace '"', '""' -replace '`', ''
        $TitleCardoptimalFontSizeEpisodetext = Get-OptimalPointSize -text $Episodetext -font $titlecardfontImagemagick -box_width $TitleCardEPMaxWidth  -box_height $TitleCardEPMaxHeight -min_pointsize $TitleCardEPminPointSize -max_pointsize $TitleCardEPmaxPointSize -lineSpacing $TitleCardEPlineSpacing
        if ($global:IsTruncated) { $TruncatedCount++ }

        $EpisodetextCAPS = $EpisodetextCAPS -replace 'â€ž', '"' -replace 'â€', '"' -replace 'â€œ', '"' -replace '"', '""' -replace '`', ''
        $TitleCardoptimalFontSizeEpisodetextCAPS = Get-OptimalPointSize -text $EpisodetextCAPS -font $titlecardfontImagemagick -box_width $TitleCardEPMaxWidth  -box_height $TitleCardEPMaxHeight -min_pointsize $TitleCardEPminPointSize -max_pointsize $TitleCardEPmaxPointSize -lineSpacing $TitleCardEPlineSpacing
        if ($global:IsTruncated) { $TruncatedCount++ }
    }

    if ($AddText -eq 'true' -or $AddBackgroundText -eq 'true' -or $AddTitleCardEPTitleText -eq 'true' -or $AddTitleCardEPText -eq 'true') {
        Write-Entry -Subtext "Finished Optimal Font Sizes for titlecards..." -Path $global:configLogging -Color Cyan -log Info
    }


    # =================================================================================
    # Process Images (Looping)
    # =================================================================================
    # POSTER PART
    Write-Entry -Subtext "Poster Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $posterPaths[$case.ID] -AddBorder $AddBorder -AddOverlay $AddOverlay -OverlayImage $DefaultPosteroverlay -BorderWidthSecond $borderwidthsecond -BorderColor $bordercolor -BorderWidth $borderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Text
        foreach ($case in $testCases) {
            Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($posterFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

            $testingargs = Get-TextOverlay-Arguments -AddStroke $AddTextStroke -InputFile $posterPaths[$case.ID] -OutputFile $posterPaths[$case.ID] -Font $fontImagemagick -PointSize $posterFontSizes[$case.ID] -FontColor $fontcolor -BoxSize $boxsize -LineSpacing $lineSpacing -TextGravity $textgravity -CaptionText $case.Text -TextOffset $text_offset -StrokeColor $strokecolor -StrokeWidth $strokewidth
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
    }
    Else {
        # Textless
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $TestPosterTextless -AddBorder $AddBorder -AddOverlay $AddOverlay -OverlayImage $DefaultPosteroverlay -BorderWidthSecond $borderwidthsecond -BorderColor $bordercolor -BorderWidth $borderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying textbox only to Poster..." -Path $global:configLogging -Color White -log Info
        $testingargsNoText = "`"$TestPosterTextless`" -size `"$boxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$text_offset`" -compose over -composite `"$TestPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
    }

    Write-Entry -Subtext "Show Poster Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $showPosterPaths[$case.ID] -AddBorder $AddBorder -AddOverlay $AddOverlay -OverlayImage $DefaultShowPosteroverlay -BorderWidthSecond $borderwidthsecond -BorderColor $bordercolor -BorderWidth $borderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Text
        foreach ($case in $testCases) {
            Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($posterFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

            $testingargs = Get-TextOverlay-Arguments -AddStroke $AddTextStroke -InputFile $showPosterPaths[$case.ID] -OutputFile $showPosterPaths[$case.ID] -Font $fontImagemagick -PointSize $posterFontSizes[$case.ID] -FontColor $fontcolor -BoxSize $boxsize -LineSpacing $lineSpacing -TextGravity $textgravity -CaptionText $case.Text -TextOffset $text_offset -StrokeColor $strokecolor -StrokeWidth $strokewidth
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
    }
    Else {
        # Textless
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $TestShowPosterTextless -AddBorder $AddBorder -AddOverlay $AddOverlay -OverlayImage $DefaultShowPosteroverlay -BorderWidthSecond $borderwidthsecond -BorderColor $bordercolor -BorderWidth $borderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying textbox only to Show Poster..." -Path $global:configLogging -Color White -log Info
        $testingargsNoText = "`"$TestShowPosterTextless`" -size `"$boxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$text_offset`" -compose over -composite `"$TestShowPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
    }

    # SEASON POSTER PART
    Write-Entry -Subtext "Season Poster Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddSeasonText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $seasonPosterPaths[$case.ID] -AddBorder $AddSeasonBorder -AddOverlay $AddSeasonOverlay -OverlayImage $Seasonoverlay -BorderWidthSecond $Seasonborderwidthsecond -BorderColor $Seasonbordercolor -BorderWidth $Seasonborderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Season Text
        foreach ($case in $testCases) {
            Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($seasonFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

            $testingargs = Get-TextOverlay-Arguments -AddStroke $AddSeasonTextStroke -InputFile $seasonPosterPaths[$case.ID] -OutputFile $seasonPosterPaths[$case.ID] -Font $fontImagemagick -PointSize $seasonFontSizes[$case.ID] -FontColor $Seasonfontcolor -BoxSize $Seasonboxsize -LineSpacing $SeasonlineSpacing -TextGravity $Seasontextgravity -CaptionText $case.Text -TextOffset $Seasontext_offset -StrokeColor $Seasonstrokecolor -StrokeWidth $Seasonstrokewidth
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Show Title on Season Text
        if ($AddShowTitletoSeason -eq 'true') {
            foreach ($case in $testCases) {
                Write-Entry -Subtext "Optimal font size for Show Title $($case.ID) text is: '$($showFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
                Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

                $testingargs = Get-TextOverlay-Arguments -AddStroke $AddSeasonTextStroke -InputFile $seasonPosterPaths[$case.ID] -OutputFile $seasonPosterPaths[$case.ID] -Font $fontImagemagick -PointSize $showFontSizes[$case.ID] -FontColor $ShowOnSeasonfontcolor -BoxSize $ShowOnSeasonboxsize -LineSpacing $ShowOnSeasonlineSpacing -TextGravity $ShowOnSeasontextgravity -CaptionText $case.Text -TextOffset $ShowOnSeasontext_offset -StrokeColor $ShowOnSeasonstrokecolor -StrokeWidth $ShowOnSeasonstrokewidth
                Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
            }
        }
    }
    Else {
        # Textless
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $testimage -OutputPath $TestSeasonPosterTextless -AddBorder $AddSeasonBorder -AddOverlay $AddSeasonOverlay -OverlayImage $Seasonoverlay -BorderWidthSecond $Seasonborderwidthsecond -BorderColor $Seasonbordercolor -BorderWidth $Seasonborderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying textbox only to Season Poster..." -Path $global:configLogging -Color White -log Info
        $testingargsNoText = "`"$TestSeasonPosterTextless`" -size `"$Seasonboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$Seasontext_offset`" -compose over -composite `"$TestSeasonPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
    }

    # BACKGROUND PART
    Write-Entry -Subtext "Background Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddBackgroundText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $backgroundPaths[$case.ID] -AddBorder $AddBackgroundBorder -AddOverlay $AddBackgroundOverlay -OverlayImage $DefaultBackgroundoverlay -BorderWidthSecond $Backgroundborderwidthsecond -BorderColor $Backgroundbordercolor -BorderWidth $Backgroundborderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Text
        foreach ($case in $testCases) {
            Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($backgroundFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

            $testingargs = Get-TextOverlay-Arguments -AddStroke $AddBackgroundTextStroke -InputFile $backgroundPaths[$case.ID] -OutputFile $backgroundPaths[$case.ID] -Font $backgroundfontImagemagick -PointSize $backgroundFontSizes[$case.ID] -FontColor $Backgroundfontcolor -BoxSize $Backgroundboxsize -LineSpacing $BackgroundlineSpacing -TextGravity $Backgroundtextgravity -CaptionText $case.Text -TextOffset $Backgroundtext_offset -StrokeColor $Backgroundstrokecolor -StrokeWidth $Backgroundstrokewidth
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
    }
    Else {
        # Textless
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $BackgroundTestPosterTextless -AddBorder $AddBackgroundBorder -AddOverlay $AddBackgroundOverlay -OverlayImage $DefaultBackgroundoverlay -BorderWidthSecond $Backgroundborderwidthsecond -BorderColor $Backgroundbordercolor -BorderWidth $Backgroundborderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying textbox only to Background..." -Path $global:configLogging -Color White -log Info
        $testingargsNoText = "`"$BackgroundTestPosterTextless`" -size `"$Backgroundboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$Backgroundtext_offset`" -compose over -composite `"$BackgroundTestPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
    }

    Write-Entry -Subtext "Show Background Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddBackgroundText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $showBackgroundPaths[$case.ID] -AddBorder $AddBackgroundBorder -AddOverlay $AddBackgroundOverlay -OverlayImage $DefaultShowBackgroundoverlay -BorderWidthSecond $Backgroundborderwidthsecond -BorderColor $Backgroundbordercolor -BorderWidth $Backgroundborderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
        # Apply Text
        foreach ($case in $testCases) {
            Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($backgroundFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

            $testingargs = Get-TextOverlay-Arguments -AddStroke $AddBackgroundTextStroke -InputFile $showBackgroundPaths[$case.ID] -OutputFile $showBackgroundPaths[$case.ID] -Font $backgroundfontImagemagick -PointSize $backgroundFontSizes[$case.ID] -FontColor $Backgroundfontcolor -BoxSize $Backgroundboxsize -LineSpacing $BackgroundlineSpacing -TextGravity $Backgroundtextgravity -CaptionText $case.Text -TextOffset $Backgroundtext_offset -StrokeColor $Backgroundstrokecolor -StrokeWidth $Backgroundstrokewidth
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }
    }
    Else {
        # Textless
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $BackgroundTestShowPosterTextless -AddBorder $AddBackgroundBorder -AddOverlay $AddBackgroundOverlay -OverlayImage $DefaultShowBackgroundoverlay -BorderWidthSecond $Backgroundborderwidthsecond -BorderColor $Backgroundbordercolor -BorderWidth $Backgroundborderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying textbox only to Show Background..." -Path $global:configLogging -Color White -log Info
        $testingargsNoText = "`"$BackgroundTestShowPosterTextless`" -size `"$Backgroundboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$Backgroundtext_offset`" -compose over -composite `"$BackgroundTestShowPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
    }

    # TITLECARD PART
    Write-Entry -Subtext "TitleCard Part:" -Path $global:configLogging -Color Green -log Info
    if ($AddTitleCardEPTitleText -eq 'true' -or $AddTitleCardEPText -eq 'true') {
        # Apply Border/Overlay
        foreach ($case in $testCases) {
            $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $titleCardPaths[$case.ID] -AddBorder $AddTitleCardBorder -AddOverlay $AddTitleCardOverlay -OverlayImage $Defaulttitlecardoverlay -BorderWidthSecond $titlecardborderwidthsecond -BorderColor $titlecardbordercolor -BorderWidth $titlecardborderwidth -LogPath $global:configLogging
            Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
        }

        # Apply Title Text
        if ($AddTitleCardEPTitleText -eq 'true') {
            foreach ($case in $testCases) {
                Write-Entry -Subtext "Optimal font size for $($case.ID) text is: '$($titleCardFontSizes[$case.ID])'" -Path $global:configLogging -Color White -log Info
                Write-Entry -Subtext "    Applying text: `"$($case.Text)`"" -Path $global:configLogging -Color White -log Info

                $testingargs = Get-TextOverlay-Arguments -AddStroke $AddTitleCardEPTitleTextStroke -InputFile $titleCardPaths[$case.ID] -OutputFile $titleCardPaths[$case.ID] -Font $titlecardfontImagemagick -PointSize $titleCardFontSizes[$case.ID] -FontColor $TitleCardEPTitlefontcolor -BoxSize $TitleCardEPTitleboxsize -LineSpacing $TitleCardEPTitlelineSpacing -TextGravity $TitleCardEPTitletextgravity -CaptionText $case.Text -TextOffset $TitleCardEPTitletext_offset -StrokeColor $TitleCardEPTitlestrokecolor -StrokeWidth $TitleCardEPTitlestrokewidth
                Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
            }
        }
        Elseif ($AddTitleCardEPText -eq 'true') {
            # Add empty box where title would go
            Write-Entry -Subtext "    Applying Title textbox only to TitleCard..." -Path $global:configLogging -Color White -log Info
            foreach ($case in $testCases) {
                $testingargsNoText = "`"$($titleCardPaths[$case.ID])`" -size `"$TitleCardEPTitleboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$TitleCardEPTitletext_offset`" -compose over -composite `"$($titleCardPaths[$case.ID])`""
                Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
            }
        }

        # Apply EP Text
        if ($AddTitleCardEPText -eq 'true') {
            Write-Entry -Subtext "Optimal font size for Episode CAPS text is: '$TitleCardoptimalFontSizeEpisodetextCAPS'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying CAPS text: `"$EpisodetextCAPS`"" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "Optimal font size for Episode text is: '$TitleCardoptimalFontSizeEpisodetext'" -Path $global:configLogging -Color White -log Info
            Write-Entry -Subtext "    Applying text: `"$Episodetext`"" -Path $global:configLogging -Color White -log Info

            foreach ($case in $testCases) {
                # first 3 use normal text, last 3 use CAPS
                $epText = if ($case.ID -like '*CAPS') { $EpisodetextCAPS } else { $Episodetext }
                $epFontSize = if ($case.ID -like '*CAPS') { $TitleCardoptimalFontSizeEpisodetextCAPS } else { $TitleCardoptimalFontSizeEpisodetext }

                $testingargs = Get-TextOverlay-Arguments -AddStroke $AddTitleCardTextStroke -InputFile $titleCardPaths[$case.ID] -OutputFile $titleCardPaths[$case.ID] -Font $titlecardfontImagemagick -PointSize $epFontSize -FontColor $TitleCardEPfontcolor -BoxSize $TitleCardEPboxsize -LineSpacing $TitleCardEPlineSpacing -TextGravity $TitleCardEPtextgravity -CaptionText $epText -TextOffset $TitleCardEPtext_offset -StrokeColor $TitleCardstrokecolor -StrokeWidth $TitleCardstrokewidth
                Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog
            }
        }
        Elseif ($AddTitleCardEPTitleText -eq 'true') {
            # Add empty box where EP text would go
            Write-Entry -Subtext "    Applying EP textbox only to TitleCard..." -Path $global:configLogging -Color White -log Info
            foreach ($case in $testCases) {
                $testingargsNoText = "`"$($titleCardPaths[$case.ID])`" -size `"$TitleCardEPboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$TitleCardEPtext_offset`" -compose over -composite `"$($titleCardPaths[$case.ID])`""
                Invoke-MagickTestCommand -Arguments $testingargsNoText -CommandLogPath $magickLog
            }
        }
    }
    Else {
        # Textless TitleCard
        $testingargs = Get-BorderOverlay-Arguments -SourceImage $backgroundtestimage -OutputPath $TitleCardTestPosterTextless -AddBorder $AddTitleCardBorder -AddOverlay $AddTitleCardOverlay -OverlayImage $Defaulttitlecardoverlay -BorderWidthSecond $titlecardborderwidthsecond -BorderColor $titlecardbordercolor -BorderWidth $titlecardborderwidth -LogPath $global:configLogging
        Invoke-MagickTestCommand -Arguments $testingargs -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying Title textbox only to TitleCard..." -Path $global:configLogging -Color White -log Info
        $testingargsNoTextTitle = "`"$TitleCardTestPosterTextless`" -size `"$TitleCardEPTitleboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$TitleCardEPTitletext_offset`" -compose over -composite `"$TitleCardTestPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoTextTitle -CommandLogPath $magickLog

        Write-Entry -Subtext "    Applying EP textbox only to TitleCard..." -Path $global:configLogging -Color White -log Info
        $testingargsNoTextEP = "`"$TitleCardTestPosterTextless`" -size `"$TitleCardEPboxsize`" xc:`"#F3AC7C`" -gravity south -geometry +0+`"$TitleCardEPtext_offset`" -compose over -composite `"$TitleCardTestPosterTextless`""
        Invoke-MagickTestCommand -Arguments $testingargsNoTextEP -CommandLogPath $magickLog
    }

    # =================================================================================
    # Finalization
    # =================================================================================

    $endTime = Get-Date
    $executionTime = New-TimeSpan -Start $startTime -End $endTime
    # Format the execution time
    $hours = [math]::Floor($executionTime.TotalHours)
    $minutes = $executionTime.Minutes
    $seconds = $executionTime.Seconds
    $FormattedTimespawn = $hours.ToString() + "h " + $minutes.ToString() + "m " + $seconds.ToString() + "s "

    Write-Entry -Subtext "Final cleanup starting..." -Path $global:configLogging -Color Green -log Info
    Write-Entry -Subtext "Deleting testimage: $testimage" -Path $global:configLogging -Color White -log Info
    Remove-Item -LiteralPath $testimage | out-null
    Write-Entry -Subtext "Deleting backgroundtestimage: $backgroundtestimage" -Path $global:configLogging -Color White -log Info
    Remove-Item -LiteralPath $backgroundtestimage | out-null

    Write-Entry -Subtext "Poster/Background/TitleCard Tests finished, you can find them here: $testDir" -Path $global:configLogging -Color Green -log Info
    Write-TextSizeCacheSummary
    Write-Entry -Message "Script execution time: $FormattedTimespawn" -Path $global:configLogging -Color Green -log Info

    $gettestimages = Get-ChildItem $testDir
    $titlecardscount = ($gettestimages | Where-Object { $_.name -like 'Title*' }).count

    # Catch both 'background' and 'showBackground'
    $backgroundsscount = ($gettestimages | Where-Object { $_.name -like '*back*' }).count

    # Catch both 'poster' and 'showPoster' (but specifically exclude SeasonPoster so it doesn't double-count)
    $posterscount = ($gettestimages | Where-Object { $_.name -like '*poster*' -and $_.name -notlike 'Season*' }).count

    $seasonscount = ($gettestimages | Where-Object { $_.name -like 'SeasonPoster*' }).count

    # Send Notification
    Send-SummaryNotification -ScriptMode $mode -FormattedTimespawn $FormattedTimespawn -ErrorCount $errorCount -TruncatedCount $TruncatedCount -PosterCount $posterscount -BackgroundCount $backgroundsscount -SeasonCount $seasonscount -EpisodeCount $titlecardscount

    if ((Test-Path "$global:ScriptRoot\Logs\ImageChoices.csv")) {
        # Calculate Summary
        $SummaryCount = Import-Csv -LiteralPath "$global:ScriptRoot\Logs\ImageChoices.csv" -Delimiter ';'
        $FallbackCount = @($SummaryCount | Where-Object Fallback -eq 'true')
        $TextlessCount = @($SummaryCount | Where-Object Language -eq 'Textless')
        $TextTruncatedCount = @($SummaryCount | Where-TextTruncated -eq 'true')
        $TextCount = @($SummaryCount | Where-Object Textless -eq 'false')
    }

    # Export json
    $jsonObject = [PSCustomObject]@{
        Posters              = if ($posterscount) { $posterscount } Else { 0 }
        Backgrounds          = if ($backgroundsscount) { $backgroundsscount } Else { 0 }
        Titlecards           = if ($titlecardscount) { $titlecardscount } Else { 0 }
        Seasons              = if ($seasonscount) { $seasonscount } Else { 0 }
        Collections          = if ($collectionCount) { $collectionCount } Else { 0 }
        Mode                 = $Mode
        Runtime              = $($hours.ToString() + ":" + $minutes.ToString() + ":" + $seconds.ToString())
        Errors               = if ($errorCount) { $errorCount } Else { 0 }
        Fallbacks            = if ($FallbackCount) { $FallbackCount } Else { 0 }
        Textless             = if ($TextlessCount) { $TextlessCount } Else { 0 }
        Truncated            = if ($TextTruncatedCount) { $TextTruncatedCount } Else { 0 }
        Text                 = if ($TextCount) { $TextCount } Else { 0 }
        "TBA Skipped"        = if ($SkipTBACount) { $SkipTBACount } Else { 0 }
        "Jap/Chines Skipped" = if ($SkipJapTitleCount) { $SkipJapTitleCount } Else { 0 }
        "Notification Sent"  = if ($global:SendNotification -eq 'true') { $global:SendNotification } Else { "false" }
        "Uptime Kuma"        = if ($global:UptimeKumaUrl) { "true" } Else { "false" }
        "Images cleared"     = if ($ImagesCleared) { $ImagesCleared } Else { 0 }
        "Folders Cleared"    = if ($PathsCleared) { $PathsCleared } Else { 0 }
        "Space saved"        = if ($savedsizestring) { $savedsizestring } Else { 0 }
        "Script Version"     = $CurrentScriptVersion
        "IM Version"         = $global:CurrentImagemagickversion
        "Start time"         = $startTime.ToString('dd.MM.yyyy HH:mm:ss')
        "End Time"           = $endTime.ToString('dd.MM.yyyy HH:mm:ss')
    }

    $jsonOutput = $jsonObject | ConvertTo-Json
    $jsonOutput | Out-File -FilePath "$global:ScriptRoot\Logs\$Mode.json" -Encoding utf8

    # Clear Running File
    if (Test-Path $CurrentlyRunning) {
        try {
            Remove-Item -LiteralPath $CurrentlyRunning -ErrorAction Stop | Out-Null
        }
        catch {
            Write-Entry -Message "Failed to delete '$CurrentlyRunning'." -Path $global:configLogging -Color Red -log Error
            Write-Entry -Subtext "Reason: $($_.Exception.Message)" -Path $global:configLogging -Color Yellow -log Error
            $global:errorCount++; Write-Entry -Subtext "[ERROR-HERE] See above. ^^^ errorCount: $errorCount" -Path $global:configLogging -Color Red -log Error
        }
    }

    if ($global:UptimeKumaUrl) {
        Send-UptimeKumaWebhook -status "up" -ping $executionTime.TotalMilliseconds
    }
